INSERT INTO public.jobs (id, user_id, plugin_id, status, input, input_file_path, result, error, progress, created_at, started_at, finished_at, celery_task_id, celery_retries) VALUES ('7c77f1b2-0500-4f73-8439-9887f4288cf5', '91d4963d-455f-4c4c-a65b-7b8676b5697f', 'property_lookup', 'completed', '{"case_id": "REQ-2026-2000"}', NULL, '{"case_id": "REQ-2026-2000", "findings": [{"category": "market_price", "tool_name": "market_price_lookup", "title": "Gi\u00e1 th\u1ecb tr\u01b0\u1eddng", "status_badge": "da_xac_thuc", "raw_findings": ["7 giao d\u1ecbch so s\u00e1nh trong b\u00e1n k\u00ednh 1.1km."], "inference_text": "Gi\u00e1 giao d\u1ecbch so s\u00e1nh dao \u0111\u1ed9ng 122.7\u2013162.1 tri\u1ec7u/m\u00b2, trung v\u1ecb kho\u1ea3ng 152.0 tri\u1ec7u/m\u00b2. Gi\u00e1 t\u01b0\u01a1ng \u0111\u1ed1i \u1ed5n \u0111\u1ecbnh qua c\u00e1c giao d\u1ecbch g\u1ea7n \u0111\u00e2y, ch\u01b0a th\u1ea5y bi\u1ebfn \u0111\u1ed9ng b\u1ea5t th\u01b0\u1eddng. N\u00ean \u01b0u ti\u00ean tr\u1ecdng s\u1ed1 cao h\u01a1n cho c\u00e1c giao d\u1ecbch g\u1ea7n \u0111\u00e2y khi \u0111\u01b0a v\u00e0o b\u01b0\u1edbc \u0111\u1ecbnh gi\u00e1.", "source_label": "market_price_lookup", "confidence_pct": 78}, {"category": "planning_zoning", "tool_name": "planning_zoning_lookup", "title": "Quy ho\u1ea1ch", "status_badge": "da_xac_thuc", "raw_findings": ["Kh\u00f4ng n\u1eb1m trong khu v\u1ef1c quy ho\u1ea1ch treo.", "L\u1ed9 gi\u1edbi h\u1ebbm/\u0111\u01b0\u1eddng d\u1ef1 ki\u1ebfn m\u1edf r\u1ed9ng l\u00ean 8m theo \u0111\u1ed3 \u00e1n quy ho\u1ea1ch 1/2000 ph\u00ea duy\u1ec7t 2021.", "Kh\u00f4ng thu\u1ed9c di\u1ec7n gi\u1ea3i to\u1ea3, thu h\u1ed3i \u0111\u1ea5t."], "inference_text": "Kh\u00f4ng c\u00f3 y\u1ebfu t\u1ed1 quy ho\u1ea1ch b\u1ea5t l\u1ee3i, c\u00f3 th\u1ec3 t\u0103ng nh\u1eb9 gi\u00e1 tr\u1ecb n\u1ebfu l\u1ed9 gi\u1edbi \u0111\u01b0\u1ee3c m\u1edf r\u1ed9ng trong 2\u20133 n\u0103m t\u1edbi nh\u1edd c\u1ea3i thi\u1ec7n kh\u1ea3 n\u0103ng ti\u1ebfp c\u1eadn.", "source_label": "planning_zoning_lookup", "confidence_pct": 93}, {"category": "legal_status", "tool_name": "legal_status_lookup", "title": "Ph\u00e1p l\u00fd", "status_badge": "luu_y", "raw_findings": ["S\u1ed5 h\u1ed3ng \u0111\u1ee9ng t\u00ean ch\u00ednh ch\u1ee7 nh\u01b0ng c\u00f3 ghi ch\u00fa th\u1ebf ch\u1ea5p \u0111\u00e3 t\u1ea5t to\u00e1n, ch\u01b0a xo\u00e1 \u0111\u0103ng k\u00fd.", "Kh\u00f4ng ghi nh\u1eadn tranh ch\u1ea5p t\u1ea1i th\u1eddi \u0111i\u1ec3m tra c\u1ee9u."], "inference_text": "C\u1ea7n y\u00eau c\u1ea7u kh\u00e1ch h\u00e0ng b\u1ed5 sung v\u0103n b\u1ea3n xo\u00e1 \u0111\u0103ng k\u00fd th\u1ebf ch\u1ea5p c\u0169 tr\u01b0\u1edbc khi ho\u00e0n t\u1ea5t h\u1ed3 s\u01a1.", "source_label": "legal_status_lookup", "confidence_pct": 55}, {"category": "neighborhood_amenity", "tool_name": "neighborhood_amenity_lookup", "title": "Ti\u1ec7n \u00edch xung quanh", "status_badge": "da_xac_thuc", "raw_findings": ["Tr\u01b0\u1eddng ti\u1ec3u h\u1ecdc: 220m \u00b7 Ch\u1ee3 d\u00e2n sinh: 460m", "Tr\u1ea1m xe bus: 352m \u00b7 B\u1ec7nh vi\u1ec7n qu\u1eadn: 0.8km"], "inference_text": "M\u1eadt \u0111\u1ed9 ti\u1ec7n \u00edch cao h\u01a1n trung b\u00ecnh khu v\u1ef1c \u2014 y\u1ebfu t\u1ed1 h\u1ed7 tr\u1ee3 t\u00edch c\u1ef1c cho nhu c\u1ea7u \u1edf th\u1ef1c v\u00e0 thanh kho\u1ea3n khi c\u1ea7n b\u00e1n l\u1ea1i.", "source_label": "neighborhood_amenity_lookup", "confidence_pct": 81}, {"category": "environmental_risk", "tool_name": "environmental_risk_lookup", "title": "M\u00f4i tr\u01b0\u1eddng", "status_badge": "luu_y", "raw_findings": ["Ghi nh\u1eadn ng\u1eadp nh\u1eb9 c\u1ee5c b\u1ed9 m\u00f9a m\u01b0a 2022\u20132023 (m\u1ee9c n\u01b0\u1edbc <20cm, r\u00fat trong ng\u00e0y).", "Kh\u00f4ng n\u1eb1m trong v\u00f9ng c\u1ea3nh b\u00e1o s\u1ea1t l\u1edf, \u00f4 nhi\u1ec5m c\u00f4ng nghi\u1ec7p."], "inference_text": "R\u1ee7i ro ng\u1eadp \u1edf m\u1ee9c th\u1ea5p, kh\u00f4ng \u1ea3nh h\u01b0\u1edfng \u0111\u00e1ng k\u1ec3 \u0111\u1ebfn gi\u00e1 tr\u1ecb \u0111\u1ecbnh gi\u00e1, nh\u01b0ng n\u00ean khuy\u1ebfn ngh\u1ecb kh\u00e1ch h\u00e0ng mua b\u1ea3o hi\u1ec3m t\u00e0i s\u1ea3n.", "source_label": "environmental_risk_lookup", "confidence_pct": 57}, {"category": "liquidity_stat", "tool_name": "liquidity_stat_lookup", "title": "Thanh kho\u1ea3n khu v\u1ef1c", "status_badge": "da_xac_thuc", "raw_findings": ["Th\u1eddi gian b\u00e1n trung b\u00ecnh: 37 ng\u00e0y \u00b7 T\u1ef7 l\u1ec7 giao d\u1ecbch th\u00e0nh c\u00f4ng: 87%", "S\u1ed1 tin rao b\u00e1n c\u00f9ng ph\u00e2n kh\u00fac trong b\u00e1n k\u00ednh 1km: 17 tin"], "inference_text": "Thanh kho\u1ea3n kh\u00e1 t\u1ed1t so v\u1edbi m\u1eb7t b\u1eb1ng chung ph\u00e2n kh\u00fac \u2014 h\u1ed7 tr\u1ee3 t\u00edch c\u1ef1c cho kh\u1ea3 n\u0103ng x\u1eed l\u00fd t\u00e0i s\u1ea3n b\u1ea3o \u0111\u1ea3m khi c\u1ea7n thi\u1ebft.", "source_label": "liquidity_stat_lookup", "confidence_pct": 94}, {"category": "stigma_reputation", "tool_name": "stigma_reputation_lookup", "title": "D\u01b0 lu\u1eadn / t\u00e2m linh", "status_badge": "da_xac_thuc", "raw_findings": ["Kh\u00f4ng ghi nh\u1eadn tin \u0111\u1ed3n hay s\u1ef1 vi\u1ec7c b\u1ea5t th\u01b0\u1eddng li\u00ean quan t\u00e0i s\u1ea3n/khu v\u1ef1c.", "Kh\u00f4ng c\u00f3 b\u00e0i b\u00e1o, h\u1ed3 s\u01a1 c\u00f4ng an ho\u1eb7c d\u1eef li\u1ec7u ti\u00eau c\u1ef1c li\u00ean quan."], "inference_text": "Kh\u00f4ng ph\u00e1t hi\u1ec7n y\u1ebfu t\u1ed1 b\u1ea5t l\u1ee3i v\u1ec1 d\u01b0 lu\u1eadn/t\u00e2m linh \u2014 kh\u00f4ng \u1ea3nh h\u01b0\u1edfng \u0111\u1ebfn gi\u00e1 tr\u1ecb hay thanh kho\u1ea3n.", "source_label": "stigma_reputation_lookup", "confidence_pct": 97}], "market_comparables": [{"address": "H\u1ebbm 39 Tr\u01b0\u1eddng Sa", "distance_km": 1.61, "area_sqm": 194.6, "transaction_date": "2025-12-23", "price_per_sqm_vnd": 141500000}, {"address": "H\u1ebbm 31 \u0110\u1ed7 Tr\u1ecdng K", "distance_km": 1.77, "area_sqm": 229.1, "transaction_date": "2026-05-30", "price_per_sqm_vnd": 122700000}, {"address": "H\u1ebbm 83 Ng\u00f4 Quy\u1ec1n", "distance_km": 0.3