INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('765ddff4-5173-4433-9054-36e02792c2aa', 'REQ-2026-2000', 'market_price', 'market_price_lookup', 'da_xac_thuc', 'Giá thị trường', '["7 giao dịch so sánh trong bán kính 1.1km."]', 'Giá giao dịch so sánh dao động 122.7–162.1 triệu/m², trung vị khoảng 152.0 triệu/m². Giá tương đối ổn định qua các giao dịch gần đây, chưa thấy biến động bất thường. Nên ưu tiên trọng số cao hơn cho các giao dịch gần đây khi đưa vào bước định giá.', 'market_price_lookup', 78);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('ce3ffb14-38cc-456f-a622-33bac686db74', 'REQ-2026-2000', 'planning_zoning', 'planning_zoning_lookup', 'da_xac_thuc', 'Quy hoạch', '["Không nằm trong khu vực quy hoạch treo.","Lộ giới hẻm/đường dự kiến mở rộng lên 8m theo đồ án quy hoạch 1/2000 phê duyệt 2021.","Không thuộc diện giải toả, thu hồi đất."]', 'Không có yếu tố quy hoạch bất lợi, có thể tăng nhẹ giá trị nếu lộ giới được mở rộng trong 2–3 năm tới nhờ cải thiện khả năng tiếp cận.', 'planning_zoning_lookup', 93);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('9b34b9e4-f6d3-4501-b43c-b2ff527f39ea', 'REQ-2026-2000', 'legal_status', 'legal_status_lookup', 'luu_y', 'Pháp lý', '["Sổ hồng đứng tên chính chủ nhưng có ghi chú thế chấp đã tất toán, chưa xoá đăng ký.","Không ghi nhận tranh chấp tại thời điểm tra cứu."]', 'Cần yêu cầu khách hàng bổ sung văn bản xoá đăng ký thế chấp cũ trước khi hoàn tất hồ sơ.', 'legal_status_lookup', 55);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('6fd596ba-4009-4382-adde-b6e6b6935469', 'REQ-2026-2000', 'neighborhood_amenity', 'neighborhood_amenity_lookup', 'da_xac_thuc', 'Tiện ích xung quanh', '["Trường tiểu học: 220m · Chợ dân sinh: 460m","Trạm xe bus: 352m · Bệnh viện quận: 0.8km"]', 'Mật độ tiện ích cao hơn trung bình khu vực — yếu tố hỗ trợ tích cực cho nhu cầu ở thực và thanh khoản khi cần bán lại.', 'neighborhood_amenity_lookup', 81);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('7740f519-604e-4dc4-a6c3-985c1f04dcd4', 'REQ-2026-2000', 'environmental_risk', 'environmental_risk_lookup', 'luu_y', 'Môi trường', '["Ghi nhận ngập nhẹ cục bộ mùa mưa 2022–2023 (mức nước <20cm, rút trong ngày).","Không nằm trong vùng cảnh báo sạt lở, ô nhiễm công nghiệp."]', 'Rủi ro ngập ở mức thấp, không ảnh hưởng đáng kể đến giá trị định giá, nhưng nên khuyến nghị khách hàng mua bảo hiểm tài sản.', 'environmental_risk_lookup', 57);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('0a2dc231-e586-4097-8bc6-6cb47366e191', 'REQ-2026-2000', 'liquidity_stat', 'liquidity_stat_lookup', 'da_xac_thuc', 'Thanh khoản khu vực', '["Thời gian bán trung bình: 37 ngày · Tỷ lệ giao dịch thành công: 87%","Số tin rao bán cùng phân khúc trong bán kính 1km: 17 tin"]', 'Thanh khoản khá tốt so với mặt bằng chung phân khúc — hỗ trợ tích cực cho khả năng xử lý tài sản bảo đảm khi cần thiết.', 'liquidity_stat_lookup', 94);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('7448e28a-8539-4d2c-a483-dd863abddfca', 'REQ-2026-2000', 'stigma_reputation', 'stigma_reputation_lookup', 'da_xac_thuc', 'Dư luận / tâm linh', '["Không ghi nhận tin đồn hay sự việc bất thường liên quan tài sản/khu vực.","Không có bài báo, hồ sơ công an hoặc dữ liệu tiêu cực liên quan."]', 'Không phát hiện yếu tố bất lợi về dư luận/tâm linh — không ảnh hưởng đến giá trị hay thanh khoản.', 'stigma_reputation_lookup', 97);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('46db6d73-ba02-497c-bf91-c305a4dda20b', 'REQ-2026-2001', 'market_price', 'market_price_lookup', 'da_xac_thuc', 'Giá thị trường', '["5 giao dịch so sánh trong bán kính 1.3km."]', 'Giá giao dịch so sánh dao động 173.9–217.6 triệu/m², trung vị khoảng 188.4 triệu/m². Xu hướng tăng theo thời gian, giao dịch gần nhất cao hơn đáng kể so với giao dịch xa nhất, cho thấy khu vực đang trong đà tăng giá. Nên ưu tiên trọng số cao hơn cho các giao dịch gần đây khi đưa vào bước định giá.', 'market_price_lookup', 87);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('fccd9d20-eeef-40c6-8370-edf8b798c3a9', 'REQ-2026-2001', 'planning_zoning', 'planning_zoning_lookup', 'luu_y', 'Quy hoạch', '["Một phần thửa đất (4m²) nằm trong hành lang lộ giới quy hoạch mở rộng đường.","Chưa có quyết định thu hồi đất chính thức tại thời điểm tra cứu."]', 'Cần đối chiếu thêm bản vẽ quy hoạch chi tiết 1/500 để xác định chính xác phần diện tích ảnh hưởng trước khi đưa vào định giá.', 'planning_zoning_lookup', 45);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('31fcf2e4-859d-4ed2-90ea-b171e94e89c8', 'REQ-2026-2001', 'legal_status', 'legal_status_lookup', 'da_xac_thuc', 'Pháp lý', '["Sổ hồng đứng tên chính chủ, cấp 16/08/2011.","Không ghi nhận tranh chấp, kê biên hay khiếu nại.","Không đang thế chấp tại tổ chức tín dụng khác."]', 'Tình trạng pháp lý sạch, đủ điều kiện nhận thế chấp. Yếu tố tích cực, giảm đáng kể rủi ro khi xử lý tài sản bảo đảm nếu phát sinh nợ xấu.', 'legal_status_lookup', 92);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('babaa79a-15d5-4a90-b9a0-2d6315774b83', 'REQ-2026-2001', 'neighborhood_amenity', 'neighborhood_amenity_lookup', 'luu_y', 'Tiện ích xung quanh', '["Trường tiểu học gần nhất: 1537m · Chợ dân sinh: 1388m","Chưa có tuyến xe bus đi qua trong bán kính 1km."]', 'Mật độ tiện ích thấp hơn trung bình khu vực, có thể ảnh hưởng nhẹ đến nhu cầu ở thực so với các vị trí trung tâm hơn.', 'neighborhood_amenity_lookup', 30);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('027a21a3-d47b-4bc5-a35f-024cf85d47ab', 'REQ-2026-2001', 'environmental_risk', 'environmental_risk_lookup', 'luu_y', 'Môi trường', '["Ghi nhận ngập nhẹ cục bộ mùa mưa 2023–2025 (mức nước <15cm, rút trong ngày).","Không nằm trong vùng cảnh báo sạt lở, ô nhiễm công nghiệp."]', 'Rủi ro ngập ở mức thấp, không ảnh hưởng đáng kể đến giá trị định giá, nhưng nên khuyến nghị khách hàng mua bảo hiểm tài sản.', 'environmental_risk_lookup', 57);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('517e9beb-6a68-45c4-b67a-f368652c61f7', 'REQ-2026-2001', 'liquidity_stat', 'liquidity_stat_lookup', 'da_xac_thuc', 'Thanh khoản khu vực', '["Thời gian bán trung bình: 48 ngày · Tỷ lệ giao dịch thành công: 92%","Số tin rao bán cùng phân khúc trong bán kính 1km: 18 tin"]', 'Thanh khoản khá tốt so với mặt bằng chung phân khúc — hỗ trợ tích cực cho khả năng xử lý tài sản bảo đảm khi cần thiết.', 'liquidity_stat_lookup', 95);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('66760efe-9195-4ccf-a7e8-1a3f3977e336', 'REQ-2026-2001', 'stigma_reputation', 'stigma_reputation_lookup', 'da_xac_thuc', 'Dư luận / tâm linh', '["Không ghi nhận tin đồn hay sự việc bất thường liên quan tài sản/khu vực.","Không có bài báo, hồ sơ công an hoặc dữ liệu tiêu cực liên quan."]', 'Không phát hiện yếu tố bất lợi về dư luận/tâm linh — không ảnh hưởng đến giá trị hay thanh khoản.', 'stigma_reputation_lookup', 89);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('cf6c279f-bfde-4969-af95-1f8463e8377a', 'REQ-2026-2002', 'market_price', 'market_price_lookup', 'da_xac_thuc', 'Giá thị trường', '["6 giao dịch so sánh trong bán kính 1.6km."]', 'Giá giao dịch so sánh dao động 200.3–273.8 triệu/m², trung vị khoảng 256.4 triệu/m². Xu hướng tăng theo thời gian, giao dịch gần nhất cao hơn đáng kể so với giao dịch xa nhất, cho thấy khu vực đang trong đà tăng giá. Nên ưu tiên trọng số cao hơn cho các giao dịch gần đây khi đưa vào bước định giá.', 'market_price_lookup', 85);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('cb9a37ab-c6d1-44b6-a886-f070e04d0853', 'REQ-2026-2006', 'environmental_risk', 'environmental_risk_lookup', 'da_xac_thuc', 'Môi trường', '["Không ghi nhận ngập úng trong 3 năm gần nhất.","Không nằm trong vùng cảnh báo sạt lở, ô nhiễm công nghiệp."]', 'Rủi ro môi trường ở mức thấp, không ảnh hưởng đáng kể đến giá trị định giá.', 'environmental_risk_lookup', 82);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('ed526695-c63c-4d22-8fdd-4a15dbe42edc', 'REQ-2026-2002', 'planning_zoning', 'planning_zoning_lookup', 'da_xac_thuc', 'Quy hoạch', '["Không nằm trong khu vực quy hoạch treo.","Lộ giới hẻm/đường dự kiến mở rộng lên 6m theo đồ án quy hoạch 1/2000 phê duyệt 2021.","Không thuộc diện giải toả, thu hồi đất."]', 'Không có yếu tố quy hoạch bất lợi, có thể tăng nhẹ giá trị nếu lộ giới được mở rộng trong 2–3 năm tới nhờ cải thiện khả năng tiếp cận.', 'planning_zoning_lookup', 89);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('45f71fd5-bd44-4a96-ab3c-00c075cb65b7', 'REQ-2026-2002', 'legal_status', 'legal_status_lookup', 'luu_y', 'Pháp lý', '["Sổ hồng đứng tên chính chủ nhưng có ghi chú thế chấp đã tất toán, chưa xoá đăng ký.","Không ghi nhận tranh chấp tại thời điểm tra cứu."]', 'Cần yêu cầu khách hàng bổ sung văn bản xoá đăng ký thế chấp cũ trước khi hoàn tất hồ sơ.', 'legal_status_lookup', 44);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('be43059b-bb5c-4c32-9b8f-8f2dfff33bc8', 'REQ-2026-2002', 'neighborhood_amenity', 'neighborhood_amenity_lookup', 'da_xac_thuc', 'Tiện ích xung quanh', '["Trường tiểu học: 487m · Chợ dân sinh: 298m","Trạm xe bus: 304m · Bệnh viện quận: 1.2km"]', 'Mật độ tiện ích cao hơn trung bình khu vực — yếu tố hỗ trợ tích cực cho nhu cầu ở thực và thanh khoản khi cần bán lại.', 'neighborhood_amenity_lookup', 82);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('dadc768f-c7fd-47d1-94e6-b2e126f29afe', 'REQ-2026-2002', 'environmental_risk', 'environmental_risk_lookup', 'luu_y', 'Môi trường', '["Ghi nhận ngập nhẹ cục bộ mùa mưa 2023–2024 (mức nước <20cm, rút trong ngày).","Không nằm trong vùng cảnh báo sạt lở, ô nhiễm công nghiệp."]', 'Rủi ro ngập ở mức thấp, không ảnh hưởng đáng kể đến giá trị định giá, nhưng nên khuyến nghị khách hàng mua bảo hiểm tài sản.', 'environmental_risk_lookup', 62);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('42a63ab7-31bf-49bf-be08-4b38260b7efe', 'REQ-2026-2002', 'liquidity_stat', 'liquidity_stat_lookup', 'da_xac_thuc', 'Thanh khoản khu vực', '["Thời gian bán trung bình: 51 ngày · Tỷ lệ giao dịch thành công: 92%","Số tin rao bán cùng phân khúc trong bán kính 1km: 13 tin"]', 'Thanh khoản khá tốt so với mặt bằng chung phân khúc — hỗ trợ tích cực cho khả năng xử lý tài sản bảo đảm khi cần thiết.', 'liquidity_stat_lookup', 80);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('e5c36feb-711e-435b-a7be-e3f0bcc4f49b', 'REQ-2026-2002', 'stigma_reputation', 'stigma_reputation_lookup', 'da_xac_thuc', 'Dư luận / tâm linh', '["Không ghi nhận tin đồn hay sự việc bất thường liên quan tài sản/khu vực.","Không có bài báo, hồ sơ công an hoặc dữ liệu tiêu cực liên quan."]', 'Không phát hiện yếu tố bất lợi về dư luận/tâm linh — không ảnh hưởng đến giá trị hay thanh khoản.', 'stigma_reputation_lookup', 88);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('f7e77aa5-47c6-4173-aa43-7fa6365c4e8a', 'REQ-2026-2003', 'market_price', 'market_price_lookup', 'da_xac_thuc', 'Giá thị trường', '["7 giao dịch so sánh trong bán kính 1.8km."]', 'Giá giao dịch so sánh dao động 115.6–160.9 triệu/m², trung vị khoảng 133.4 triệu/m². Giá tương đối ổn định qua các giao dịch gần đây, chưa thấy biến động bất thường. Nên ưu tiên trọng số cao hơn cho các giao dịch gần đây khi đưa vào bước định giá.', 'market_price_lookup', 87);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('15ef99fd-e0f1-49f7-a95e-c6a45921953b', 'REQ-2026-2003', 'planning_zoning', 'planning_zoning_lookup', 'da_xac_thuc', 'Quy hoạch', '["Không nằm trong khu vực quy hoạch treo.","Lộ giới hẻm/đường dự kiến giữ nguyên theo đồ án quy hoạch 1/2000 phê duyệt 2023.","Không thuộc diện giải toả, thu hồi đất."]', 'Không có yếu tố quy hoạch bất lợi, có thể tăng nhẹ giá trị nếu lộ giới được mở rộng trong 2–3 năm tới nhờ cải thiện khả năng tiếp cận.', 'planning_zoning_lookup', 80);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('7681ca75-3f1a-4808-a1de-bbca48c304c9', 'REQ-2026-2003', 'legal_status', 'legal_status_lookup', 'da_xac_thuc', 'Pháp lý', '["Sổ hồng đứng tên chính chủ, cấp 14/03/2019.","Không ghi nhận tranh chấp, kê biên hay khiếu nại.","Không đang thế chấp tại tổ chức tín dụng khác."]', 'Tình trạng pháp lý sạch, đủ điều kiện nhận thế chấp. Yếu tố tích cực, giảm đáng kể rủi ro khi xử lý tài sản bảo đảm nếu phát sinh nợ xấu.', 'legal_status_lookup', 85);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('ab880bac-eded-411d-9083-81357bbf31d6', 'REQ-2026-2003', 'neighborhood_amenity', 'neighborhood_amenity_lookup', 'da_xac_thuc', 'Tiện ích xung quanh', '["Trường tiểu học: 344m · Chợ dân sinh: 367m","Trạm xe bus: 208m · Bệnh viện quận: 1.5km"]', 'Mật độ tiện ích cao hơn trung bình khu vực — yếu tố hỗ trợ tích cực cho nhu cầu ở thực và thanh khoản khi cần bán lại.', 'neighborhood_amenity_lookup', 90);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('4e661bf0-843c-4b12-8719-528f795003fe', 'REQ-2026-2003', 'environmental_risk', 'environmental_risk_lookup', 'luu_y', 'Môi trường', '["Ghi nhận ngập nhẹ cục bộ mùa mưa 2024–2024 (mức nước <15cm, rút trong ngày).","Không nằm trong vùng cảnh báo sạt lở, ô nhiễm công nghiệp."]', 'Rủi ro ngập ở mức thấp, không ảnh hưởng đáng kể đến giá trị định giá, nhưng nên khuyến nghị khách hàng mua bảo hiểm tài sản.', 'environmental_risk_lookup', 46);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('4d2e80ef-c7f5-4f24-87db-50d9585d9ede', 'REQ-2026-2003', 'liquidity_stat', 'liquidity_stat_lookup', 'luu_y', 'Thanh khoản khu vực', '["Thời gian bán trung bình: 120 ngày · Tỷ lệ giao dịch thành công: 45%","Số tin rao bán cùng phân khúc trong bán kính 1km: 5 tin"]', 'Thanh khoản thấp hơn mặt bằng chung khu vực — cần cân nhắc thêm khi xác định LTV để đảm bảo khả năng xử lý tài sản bảo đảm.', 'liquidity_stat_lookup', 33);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('de203ffd-fc8a-44d0-8e60-4d3f305650fd', 'REQ-2026-2003', 'stigma_reputation', 'stigma_reputation_lookup', 'chua_xac_thuc', 'Dư luận / tâm linh', '["Ghi nhận tin đồn dân cư chưa xác thực liên quan 1 sự việc năm 2020.","Không có bài báo, hồ sơ công an hoặc dữ liệu chính thức xác nhận."]', 'Độ tin cậy nguồn tin thấp, chưa đủ cơ sở kết luận ảnh hưởng đến giá trị hay thanh khoản. Khuyến nghị thẩm định viên xác minh thực địa trước khi đưa vào báo cáo chính thức.', 'stigma_reputation_lookup', 44);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('abe89b45-ff50-4b77-b8f4-94138eb36432', 'REQ-2026-2004', 'market_price', 'market_price_lookup', 'da_xac_thuc', 'Giá thị trường', '["6 giao dịch so sánh trong bán kính 1.3km."]', 'Giá giao dịch so sánh dao động 160.2–204.9 triệu/m², trung vị khoảng 177.7 triệu/m². Xu hướng tăng theo thời gian, giao dịch gần nhất cao hơn đáng kể so với giao dịch xa nhất, cho thấy khu vực đang trong đà tăng giá. Nên ưu tiên trọng số cao hơn cho các giao dịch gần đây khi đưa vào bước định giá.', 'market_price_lookup', 86);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('91fa61ce-dddd-4b00-8947-19c5345bc25f', 'REQ-2026-2004', 'planning_zoning', 'planning_zoning_lookup', 'da_xac_thuc', 'Quy hoạch', '["Không nằm trong khu vực quy hoạch treo.","Lộ giới hẻm/đường dự kiến mở rộng lên 4m theo đồ án quy hoạch 1/2000 phê duyệt 2021.","Không thuộc diện giải toả, thu hồi đất."]', 'Không có yếu tố quy hoạch bất lợi, có thể tăng nhẹ giá trị nếu lộ giới được mở rộng trong 2–3 năm tới nhờ cải thiện khả năng tiếp cận.', 'planning_zoning_lookup', 87);
