INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('d9f70b31-433f-4e41-88c9-2b307f4b366c', 'REQ-2026-2005', 'stigma_reputation', 'stigma_reputation_lookup', 'chua_xac_thuc', 'Dư luận / tâm linh', '["Ghi nhận tin đồn dân cư chưa xác thực liên quan 1 sự việc năm 2022.","Không có bài báo, hồ sơ công an hoặc dữ liệu chính thức xác nhận."]', 'Độ tin cậy nguồn tin thấp, chưa đủ cơ sở kết luận ảnh hưởng đến giá trị hay thanh khoản. Khuyến nghị thẩm định viên xác minh thực địa trước khi đưa vào báo cáo chính thức.', 'stigma_reputation_lookup', 39);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('0dbb7b89-0b49-415a-890e-7545a19bde94', 'REQ-2026-2006', 'market_price', 'market_price_lookup', 'da_xac_thuc', 'Giá thị trường', '["7 giao dịch so sánh trong bán kính 1.2km."]', 'Giá giao dịch so sánh dao động 106.8–130.0 triệu/m², trung vị khoảng 118.4 triệu/m². Giá tương đối ổn định qua các giao dịch gần đây, chưa thấy biến động bất thường. Nên ưu tiên trọng số cao hơn cho các giao dịch gần đây khi đưa vào bước định giá.', 'market_price_lookup', 78);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('a41ccc68-14e6-4780-ab25-f750c14b79f5', 'REQ-2026-2006', 'planning_zoning', 'planning_zoning_lookup', 'luu_y', 'Quy hoạch', '["Một phần thửa đất (7m²) nằm trong hành lang lộ giới quy hoạch mở rộng đường.","Chưa có quyết định thu hồi đất chính thức tại thời điểm tra cứu."]', 'Cần đối chiếu thêm bản vẽ quy hoạch chi tiết 1/500 để xác định chính xác phần diện tích ảnh hưởng trước khi đưa vào định giá.', 'planning_zoning_lookup', 60);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('c4577d30-5a86-4a23-bc7e-64b4b16cb42b', 'REQ-2026-2006', 'legal_status', 'legal_status_lookup', 'luu_y', 'Pháp lý', '["Sổ hồng đứng tên chính chủ nhưng có ghi chú thế chấp đã tất toán, chưa xoá đăng ký.","Không ghi nhận tranh chấp tại thời điểm tra cứu."]', 'Cần yêu cầu khách hàng bổ sung văn bản xoá đăng ký thế chấp cũ trước khi hoàn tất hồ sơ.', 'legal_status_lookup', 48);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('519d05a3-41f3-436f-9235-75dbae28a4ab', 'REQ-2026-2006', 'neighborhood_amenity', 'neighborhood_amenity_lookup', 'luu_y', 'Tiện ích xung quanh', '["Trường tiểu học gần nhất: 1893m · Chợ dân sinh: 1823m","Chưa có tuyến xe bus đi qua trong bán kính 1km."]', 'Mật độ tiện ích thấp hơn trung bình khu vực, có thể ảnh hưởng nhẹ đến nhu cầu ở thực so với các vị trí trung tâm hơn.', 'neighborhood_amenity_lookup', 37);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('c00dcfbf-c612-414d-b3b0-c8e681869ad4', 'REQ-2026-2006', 'liquidity_stat', 'liquidity_stat_lookup', 'da_xac_thuc', 'Thanh khoản khu vực', '["Thời gian bán trung bình: 55 ngày · Tỷ lệ giao dịch thành công: 82%","Số tin rao bán cùng phân khúc trong bán kính 1km: 21 tin"]', 'Thanh khoản khá tốt so với mặt bằng chung phân khúc — hỗ trợ tích cực cho khả năng xử lý tài sản bảo đảm khi cần thiết.', 'liquidity_stat_lookup', 92);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('e3594d22-82be-4f92-add9-0b67d19aae39', 'REQ-2026-2006', 'stigma_reputation', 'stigma_reputation_lookup', 'chua_xac_thuc', 'Dư luận / tâm linh', '["Ghi nhận tin đồn dân cư chưa xác thực liên quan 1 sự việc năm 2020.","Không có bài báo, hồ sơ công an hoặc dữ liệu chính thức xác nhận."]', 'Độ tin cậy nguồn tin thấp, chưa đủ cơ sở kết luận ảnh hưởng đến giá trị hay thanh khoản. Khuyến nghị thẩm định viên xác minh thực địa trước khi đưa vào báo cáo chính thức.', 'stigma_reputation_lookup', 35);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('cd8270b9-a306-452f-8096-e8a7e53fddbe', 'REQ-2026-2008', 'market_price', 'market_price_lookup', 'da_xac_thuc', 'Giá thị trường', '["8 giao dịch so sánh trong bán kính 0.9km."]', 'Giá giao dịch so sánh dao động 150.9–217.0 triệu/m², trung vị khoảng 189.4 triệu/m². Xu hướng tăng theo thời gian, giao dịch gần nhất cao hơn đáng kể so với giao dịch xa nhất, cho thấy khu vực đang trong đà tăng giá. Nên ưu tiên trọng số cao hơn cho các giao dịch gần đây khi đưa vào bước định giá.', 'market_price_lookup', 88);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('f3e2b75e-26a5-432c-9a52-6d734c2754f8', 'REQ-2026-2008', 'planning_zoning', 'planning_zoning_lookup', 'da_xac_thuc', 'Quy hoạch', '["Không nằm trong khu vực quy hoạch treo.","Lộ giới hẻm/đường dự kiến mở rộng lên 4m theo đồ án quy hoạch 1/2000 phê duyệt 2020.","Không thuộc diện giải toả, thu hồi đất."]', 'Không có yếu tố quy hoạch bất lợi, có thể tăng nhẹ giá trị nếu lộ giới được mở rộng trong 2–3 năm tới nhờ cải thiện khả năng tiếp cận.', 'planning_zoning_lookup', 81);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('a8e13c4e-50a2-40e9-8dfe-4db0eb31899e', 'REQ-2026-2008', 'legal_status', 'legal_status_lookup', 'da_xac_thuc', 'Pháp lý', '["Sổ hồng đứng tên chính chủ, cấp 09/08/2018.","Không ghi nhận tranh chấp, kê biên hay khiếu nại.","Không đang thế chấp tại tổ chức tín dụng khác."]', 'Tình trạng pháp lý sạch, đủ điều kiện nhận thế chấp. Yếu tố tích cực, giảm đáng kể rủi ro khi xử lý tài sản bảo đảm nếu phát sinh nợ xấu.', 'legal_status_lookup', 95);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('d67dd373-fe7f-443c-a6a0-101a66ec0b5d', 'REQ-2026-2008', 'neighborhood_amenity', 'neighborhood_amenity_lookup', 'da_xac_thuc', 'Tiện ích xung quanh', '["Trường tiểu học: 362m · Chợ dân sinh: 339m","Trạm xe bus: 210m · Bệnh viện quận: 2.0km"]', 'Mật độ tiện ích cao hơn trung bình khu vực — yếu tố hỗ trợ tích cực cho nhu cầu ở thực và thanh khoản khi cần bán lại.', 'neighborhood_amenity_lookup', 83);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('2b62c3dd-263c-44b9-aabe-c37ac1629472', 'REQ-2026-2008', 'environmental_risk', 'environmental_risk_lookup', 'da_xac_thuc', 'Môi trường', '["Không ghi nhận ngập úng trong 3 năm gần nhất.","Không nằm trong vùng cảnh báo sạt lở, ô nhiễm công nghiệp."]', 'Rủi ro môi trường ở mức thấp, không ảnh hưởng đáng kể đến giá trị định giá.', 'environmental_risk_lookup', 83);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('52156128-e51f-4041-99c7-9fd38ae6e7d4', 'REQ-2026-2008', 'liquidity_stat', 'liquidity_stat_lookup', 'da_xac_thuc', 'Thanh khoản khu vực', '["Thời gian bán trung bình: 46 ngày · Tỷ lệ giao dịch thành công: 90%","Số tin rao bán cùng phân khúc trong bán kính 1km: 16 tin"]', 'Thanh khoản khá tốt so với mặt bằng chung phân khúc — hỗ trợ tích cực cho khả năng xử lý tài sản bảo đảm khi cần thiết.', 'liquidity_stat_lookup', 89);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('94795490-0d1f-4ab0-92cf-6d9180f9413f', 'REQ-2026-2008', 'stigma_reputation', 'stigma_reputation_lookup', 'da_xac_thuc', 'Dư luận / tâm linh', '["Không ghi nhận tin đồn hay sự việc bất thường liên quan tài sản/khu vực.","Không có bài báo, hồ sơ công an hoặc dữ liệu tiêu cực liên quan."]', 'Không phát hiện yếu tố bất lợi về dư luận/tâm linh — không ảnh hưởng đến giá trị hay thanh khoản.', 'stigma_reputation_lookup', 92);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('16087fdb-1898-4118-a023-f7d70f6fef59', 'REQ-2026-2009', 'market_price', 'market_price_lookup', 'da_xac_thuc', 'Giá thị trường', '["6 giao dịch so sánh trong bán kính 1.5km."]', 'Giá giao dịch so sánh dao động 60.3–85.6 triệu/m², trung vị khoảng 77.0 triệu/m². Giá tương đối ổn định qua các giao dịch gần đây, chưa thấy biến động bất thường. Nên ưu tiên trọng số cao hơn cho các giao dịch gần đây khi đưa vào bước định giá.', 'market_price_lookup', 91);
