INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('ceb555da-12d3-4cad-a6d0-ad43a77e99ec', 'REQ-2026-2010', 'environmental_risk', 'environmental_risk_lookup', 'da_xac_thuc', 'Môi trường', '["Không ghi nhận ngập úng trong 3 năm gần nhất.","Không nằm trong vùng cảnh báo sạt lở, ô nhiễm công nghiệp."]', 'Rủi ro môi trường ở mức thấp, không ảnh hưởng đáng kể đến giá trị định giá.', 'environmental_risk_lookup', 95);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('4f2427f9-6505-42c5-b75c-664fa20bf457', 'REQ-2026-2010', 'liquidity_stat', 'liquidity_stat_lookup', 'da_xac_thuc', 'Thanh khoản khu vực', '["Thời gian bán trung bình: 50 ngày · Tỷ lệ giao dịch thành công: 91%","Số tin rao bán cùng phân khúc trong bán kính 1km: 12 tin"]', 'Thanh khoản khá tốt so với mặt bằng chung phân khúc — hỗ trợ tích cực cho khả năng xử lý tài sản bảo đảm khi cần thiết.', 'liquidity_stat_lookup', 82);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('003b0e34-6129-4494-abe6-78066201a516', 'REQ-2026-2010', 'stigma_reputation', 'stigma_reputation_lookup', 'chua_xac_thuc', 'Dư luận / tâm linh', '["Ghi nhận tin đồn dân cư chưa xác thực liên quan 1 sự việc năm 2016.","Không có bài báo, hồ sơ công an hoặc dữ liệu chính thức xác nhận."]', 'Độ tin cậy nguồn tin thấp, chưa đủ cơ sở kết luận ảnh hưởng đến giá trị hay thanh khoản. Khuyến nghị thẩm định viên xác minh thực địa trước khi đưa vào báo cáo chính thức.', 'stigma_reputation_lookup', 57);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('5a43742b-36a2-4122-a546-96cc7e5f9154', 'REQ-2026-2011', 'market_price', 'market_price_lookup', 'da_xac_thuc', 'Giá thị trường', '["5 giao dịch so sánh trong bán kính 1.4km."]', 'Giá giao dịch so sánh dao động 72.0–102.9 triệu/m², trung vị khoảng 84.6 triệu/m². Giá tương đối ổn định qua các giao dịch gần đây, chưa thấy biến động bất thường. Nên ưu tiên trọng số cao hơn cho các giao dịch gần đây khi đưa vào bước định giá.', 'market_price_lookup', 92);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('7d743b02-08c6-4c84-b898-726f252a5417', 'REQ-2026-2011', 'planning_zoning', 'planning_zoning_lookup', 'da_xac_thuc', 'Quy hoạch', '["Không nằm trong khu vực quy hoạch treo.","Lộ giới hẻm/đường dự kiến mở rộng lên 8m theo đồ án quy hoạch 1/2000 phê duyệt 2020.","Không thuộc diện giải toả, thu hồi đất."]', 'Không có yếu tố quy hoạch bất lợi, có thể tăng nhẹ giá trị nếu lộ giới được mở rộng trong 2–3 năm tới nhờ cải thiện khả năng tiếp cận.', 'planning_zoning_lookup', 83);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('f59e5f4d-dadb-4989-85e9-2c81b1c39d8e', 'REQ-2026-2011', 'legal_status', 'legal_status_lookup', 'luu_y', 'Pháp lý', '["Sổ hồng đứng tên chính chủ nhưng có ghi chú thế chấp đã tất toán, chưa xoá đăng ký.","Không ghi nhận tranh chấp tại thời điểm tra cứu."]', 'Cần yêu cầu khách hàng bổ sung văn bản xoá đăng ký thế chấp cũ trước khi hoàn tất hồ sơ.', 'legal_status_lookup', 38);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('51b8bbac-1a1d-4b14-a645-bbcbc2417102', 'REQ-2026-2011', 'neighborhood_amenity', 'neighborhood_amenity_lookup', 'da_xac_thuc', 'Tiện ích xung quanh', '["Trường tiểu học: 402m · Chợ dân sinh: 213m","Trạm xe bus: 284m · Bệnh viện quận: 1.7km"]', 'Mật độ tiện ích cao hơn trung bình khu vực — yếu tố hỗ trợ tích cực cho nhu cầu ở thực và thanh khoản khi cần bán lại.', 'neighborhood_amenity_lookup', 91);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('f341ad0f-bdd8-42b8-83f2-2869814d8397', 'REQ-2026-2011', 'environmental_risk', 'environmental_risk_lookup', 'da_xac_thuc', 'Môi trường', '["Không ghi nhận ngập úng trong 3 năm gần nhất.","Không nằm trong vùng cảnh báo sạt lở, ô nhiễm công nghiệp."]', 'Rủi ro môi trường ở mức thấp, không ảnh hưởng đáng kể đến giá trị định giá.', 'environmental_risk_lookup', 97);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('0d07e5b1-78ef-4466-a0c0-2406cd96136a', 'REQ-2026-2011', 'liquidity_stat', 'liquidity_stat_lookup', 'da_xac_thuc', 'Thanh khoản khu vực', '["Thời gian bán trung bình: 53 ngày · Tỷ lệ giao dịch thành công: 77%","Số tin rao bán cùng phân khúc trong bán kính 1km: 9 tin"]', 'Thanh khoản khá tốt so với mặt bằng chung phân khúc — hỗ trợ tích cực cho khả năng xử lý tài sản bảo đảm khi cần thiết.', 'liquidity_stat_lookup', 89);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('54fff12f-03f7-4bad-84ec-9d2539a1fdd2', 'REQ-2026-2011', 'stigma_reputation', 'stigma_reputation_lookup', 'da_xac_thuc', 'Dư luận / tâm linh', '["Không ghi nhận tin đồn hay sự việc bất thường liên quan tài sản/khu vực.","Không có bài báo, hồ sơ công an hoặc dữ liệu tiêu cực liên quan."]', 'Không phát hiện yếu tố bất lợi về dư luận/tâm linh — không ảnh hưởng đến giá trị hay thanh khoản.', 'stigma_reputation_lookup', 95);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('84907a0f-f1ba-4dac-9a1d-aa84a4f6c67b', 'REQ-2026-2012', 'market_price', 'market_price_lookup', 'da_xac_thuc', 'Giá thị trường', '["6 giao dịch so sánh trong bán kính 1.2km."]', 'Giá giao dịch so sánh dao động 319.9–377.7 triệu/m², trung vị khoảng 363.4 triệu/m². Xu hướng tăng theo thời gian, giao dịch gần nhất cao hơn đáng kể so với giao dịch xa nhất, cho thấy khu vực đang trong đà tăng giá. Nên ưu tiên trọng số cao hơn cho các giao dịch gần đây khi đưa vào bước định giá.', 'market_price_lookup', 71);
