INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('d7e30a58-6b91-4b82-82c0-5935c8f5f8f8', 'REQ-2026-2019', 'legal_status', 'legal_status_lookup', 'da_xac_thuc', 'Pháp lý', '["Sổ hồng đứng tên chính chủ, cấp 08/07/2015.","Không ghi nhận tranh chấp, kê biên hay khiếu nại.","Không đang thế chấp tại tổ chức tín dụng khác."]', 'Tình trạng pháp lý sạch, đủ điều kiện nhận thế chấp. Yếu tố tích cực, giảm đáng kể rủi ro khi xử lý tài sản bảo đảm nếu phát sinh nợ xấu.', 'legal_status_lookup', 88);
