INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('884bbc98-67b5-4fe0-8292-ccdefc4eae6d', 'REQ-2026-2021', 'liquidity_stat', 'liquidity_stat_lookup', 'luu_y', 'Thanh khoản khu vực', '["Thời gian bán trung bình: 106 ngày · Tỷ lệ giao dịch thành công: 47%","Số tin rao bán cùng phân khúc trong bán kính 1km: 5 tin"]', 'Thanh khoản thấp hơn mặt bằng chung khu vực — cần cân nhắc thêm khi xác định LTV để đảm bảo khả năng xử lý tài sản bảo đảm.', 'liquidity_stat_lookup', 54);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('5600943f-e907-4aed-9d00-273c93f33b5d', 'REQ-2026-2021', 'stigma_reputation', 'stigma_reputation_lookup', 'da_xac_thuc', 'Dư luận / tâm linh', '["Không ghi nhận tin đồn hay sự việc bất thường liên quan tài sản/khu vực.","Không có bài báo, hồ sơ công an hoặc dữ liệu tiêu cực liên quan."]', 'Không phát hiện yếu tố bất lợi về dư luận/tâm linh — không ảnh hưởng đến giá trị hay thanh khoản.', 'stigma_reputation_lookup', 92);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('ace9ca6c-1b6a-4481-9e9c-cc06945761a8', 'REQ-2026-2022', 'market_price', 'market_price_lookup', 'da_xac_thuc', 'Giá thị trường', '["4 giao dịch so sánh trong bán kính 1.6km."]', 'Giá giao dịch so sánh dao động 84.0–107.5 triệu/m², trung vị khoảng 99.3 triệu/m². Xu hướng tăng theo thời gian, giao dịch gần nhất cao hơn đáng kể so với giao dịch xa nhất, cho thấy khu vực đang trong đà tăng giá. Nên ưu tiên trọng số cao hơn cho các giao dịch gần đây khi đưa vào bước định giá.', 'market_price_lookup', 71);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('1c5db00e-16ab-4f50-8faf-2fe1e68bdbc8', 'REQ-2026-2022', 'planning_zoning', 'planning_zoning_lookup', 'da_xac_thuc', 'Quy hoạch', '["Không nằm trong khu vực quy hoạch treo.","Lộ giới hẻm/đường dự kiến giữ nguyên theo đồ án quy hoạch 1/2000 phê duyệt 2021.","Không thuộc diện giải toả, thu hồi đất."]', 'Không có yếu tố quy hoạch bất lợi, có thể tăng nhẹ giá trị nếu lộ giới được mở rộng trong 2–3 năm tới nhờ cải thiện khả năng tiếp cận.', 'planning_zoning_lookup', 86);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('fdf8bcde-041f-4a2f-86ac-6a7f59fe61fa', 'REQ-2026-2022', 'legal_status', 'legal_status_lookup', 'da_xac_thuc', 'Pháp lý', '["Sổ hồng đứng tên chính chủ, cấp 27/08/2021.","Không ghi nhận tranh chấp, kê biên hay khiếu nại.","Không đang thế chấp tại tổ chức tín dụng khác."]', 'Tình trạng pháp lý sạch, đủ điều kiện nhận thế chấp. Yếu tố tích cực, giảm đáng kể rủi ro khi xử lý tài sản bảo đảm nếu phát sinh nợ xấu.', 'legal_status_lookup', 92);
