INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('8f44cb8b-2823-44ba-bf62-9cefcdbb149a', 'REQ-2026-2027', 'legal_status', 'legal_status_lookup', 'luu_y', 'Pháp lý', '["Sổ hồng đứng tên chính chủ nhưng có ghi chú thế chấp đã tất toán, chưa xoá đăng ký.","Không ghi nhận tranh chấp tại thời điểm tra cứu."]', 'Cần yêu cầu khách hàng bổ sung văn bản xoá đăng ký thế chấp cũ trước khi hoàn tất hồ sơ.', 'legal_status_lookup', 50);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('16c2c183-e1d0-4176-bbaa-1f31ed7cbe9b', 'REQ-2026-2027', 'neighborhood_amenity', 'neighborhood_amenity_lookup', 'da_xac_thuc', 'Tiện ích xung quanh', '["Trường tiểu học: 208m · Chợ dân sinh: 397m","Trạm xe bus: 231m · Bệnh viện quận: 1.6km"]', 'Mật độ tiện ích cao hơn trung bình khu vực — yếu tố hỗ trợ tích cực cho nhu cầu ở thực và thanh khoản khi cần bán lại.', 'neighborhood_amenity_lookup', 89);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('177aa8a0-64d4-4a6d-af45-56dc49c3d4f6', 'REQ-2026-2027', 'environmental_risk', 'environmental_risk_lookup', 'da_xac_thuc', 'Môi trường', '["Không ghi nhận ngập úng trong 3 năm gần nhất.","Không nằm trong vùng cảnh báo sạt lở, ô nhiễm công nghiệp."]', 'Rủi ro môi trường ở mức thấp, không ảnh hưởng đáng kể đến giá trị định giá.', 'environmental_risk_lookup', 96);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('a6fcbcb2-ccc8-43aa-a8df-6365ae06c329', 'REQ-2026-2027', 'liquidity_stat', 'liquidity_stat_lookup', 'luu_y', 'Thanh khoản khu vực', '["Thời gian bán trung bình: 113 ngày · Tỷ lệ giao dịch thành công: 61%","Số tin rao bán cùng phân khúc trong bán kính 1km: 5 tin"]', 'Thanh khoản thấp hơn mặt bằng chung khu vực — cần cân nhắc thêm khi xác định LTV để đảm bảo khả năng xử lý tài sản bảo đảm.', 'liquidity_stat_lookup', 58);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('d290816b-e5a2-4b95-aac5-05cf8e26f018', 'REQ-2026-2027', 'stigma_reputation', 'stigma_reputation_lookup', 'da_xac_thuc', 'Dư luận / tâm linh', '["Không ghi nhận tin đồn hay sự việc bất thường liên quan tài sản/khu vực.","Không có bài báo, hồ sơ công an hoặc dữ liệu tiêu cực liên quan."]', 'Không phát hiện yếu tố bất lợi về dư luận/tâm linh — không ảnh hưởng đến giá trị hay thanh khoản.', 'stigma_reputation_lookup', 89);
