INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('68a5e0c7-7ce3-4e33-8255-ef8ed43feee4', 'REQ-2026-2030', 'liquidity_stat', 'liquidity_stat_lookup', 'luu_y', 'Thanh khoản khu vực', '["Thời gian bán trung bình: 113 ngày · Tỷ lệ giao dịch thành công: 56%","Số tin rao bán cùng phân khúc trong bán kính 1km: 4 tin"]', 'Thanh khoản thấp hơn mặt bằng chung khu vực — cần cân nhắc thêm khi xác định LTV để đảm bảo khả năng xử lý tài sản bảo đảm.', 'liquidity_stat_lookup', 47);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('84db69ec-3f14-4ed6-ad50-60c6d199053d', 'REQ-2026-2030', 'stigma_reputation', 'stigma_reputation_lookup', 'da_xac_thuc', 'Dư luận / tâm linh', '["Không ghi nhận tin đồn hay sự việc bất thường liên quan tài sản/khu vực.","Không có bài báo, hồ sơ công an hoặc dữ liệu tiêu cực liên quan."]', 'Không phát hiện yếu tố bất lợi về dư luận/tâm linh — không ảnh hưởng đến giá trị hay thanh khoản.', 'stigma_reputation_lookup', 84);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('7f786386-66ce-47f1-af08-43626e9daf84', 'REQ-2026-2032', 'market_price', 'market_price_lookup', 'da_xac_thuc', 'Giá thị trường', '["4 giao dịch so sánh trong bán kính 1.5km."]', 'Giá giao dịch so sánh dao động 45.3–58.3 triệu/m², trung vị khoảng 52.9 triệu/m². Xu hướng tăng theo thời gian, giao dịch gần nhất cao hơn đáng kể so với giao dịch xa nhất, cho thấy khu vực đang trong đà tăng giá. Nên ưu tiên trọng số cao hơn cho các giao dịch gần đây khi đưa vào bước định giá.', 'market_price_lookup', 78);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('2a37dc9e-0422-4cbb-8396-911b97711e78', 'REQ-2026-2032', 'planning_zoning', 'planning_zoning_lookup', 'da_xac_thuc', 'Quy hoạch', '["Không nằm trong khu vực quy hoạch treo.","Lộ giới hẻm/đường dự kiến mở rộng lên 4m theo đồ án quy hoạch 1/2000 phê duyệt 2020.","Không thuộc diện giải toả, thu hồi đất."]', 'Không có yếu tố quy hoạch bất lợi, có thể tăng nhẹ giá trị nếu lộ giới được mở rộng trong 2–3 năm tới nhờ cải thiện khả năng tiếp cận.', 'planning_zoning_lookup', 89);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('066d955b-4b57-46cb-8cf0-144691d7e9e5', 'REQ-2026-2032', 'legal_status', 'legal_status_lookup', 'da_xac_thuc', 'Pháp lý', '["Sổ hồng đứng tên chính chủ, cấp 15/10/2019.","Không ghi nhận tranh chấp, kê biên hay khiếu nại.","Không đang thế chấp tại tổ chức tín dụng khác."]', 'Tình trạng pháp lý sạch, đủ điều kiện nhận thế chấp. Yếu tố tích cực, giảm đáng kể rủi ro khi xử lý tài sản bảo đảm nếu phát sinh nợ xấu.', 'legal_status_lookup', 88);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('134de824-c321-460c-86e5-fd9921784d5d', 'REQ-2026-2032', 'neighborhood_amenity', 'neighborhood_amenity_lookup', 'luu_y', 'Tiện ích xung quanh', '["Trường tiểu học gần nhất: 2207m · Chợ dân sinh: 1192m","Chưa có tuyến xe bus đi qua trong bán kính 1km."]', 'Mật độ tiện ích thấp hơn trung bình khu vực, có thể ảnh hưởng nhẹ đến nhu cầu ở thực so với các vị trí trung tâm hơn.', 'neighborhood_amenity_lookup', 50);
