INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('c4c6d809-eb69-48ca-a1f6-0cf550b70fa0', 'REQ-2026-2035', 'market_price', 'market_price_lookup', 'da_xac_thuc', 'Giá thị trường', '["6 giao dịch so sánh trong bán kính 1.2km."]', 'Giá giao dịch so sánh dao động 162.6–210.7 triệu/m², trung vị khoảng 188.6 triệu/m². Giá tương đối ổn định qua các giao dịch gần đây, chưa thấy biến động bất thường. Nên ưu tiên trọng số cao hơn cho các giao dịch gần đây khi đưa vào bước định giá.', 'market_price_lookup', 71);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('0059f219-dead-41cd-af3c-545f253d28c2', 'REQ-2026-2035', 'planning_zoning', 'planning_zoning_lookup', 'da_xac_thuc', 'Quy hoạch', '["Không nằm trong khu vực quy hoạch treo.","Lộ giới hẻm/đường dự kiến mở rộng lên 4m theo đồ án quy hoạch 1/2000 phê duyệt 2023.","Không thuộc diện giải toả, thu hồi đất."]', 'Không có yếu tố quy hoạch bất lợi, có thể tăng nhẹ giá trị nếu lộ giới được mở rộng trong 2–3 năm tới nhờ cải thiện khả năng tiếp cận.', 'planning_zoning_lookup', 88);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('073099e8-b338-4f0a-84a4-abdaf6ab84c9', 'REQ-2026-2035', 'legal_status', 'legal_status_lookup', 'da_xac_thuc', 'Pháp lý', '["Sổ hồng đứng tên chính chủ, cấp 11/07/2009.","Không ghi nhận tranh chấp, kê biên hay khiếu nại.","Không đang thế chấp tại tổ chức tín dụng khác."]', 'Tình trạng pháp lý sạch, đủ điều kiện nhận thế chấp. Yếu tố tích cực, giảm đáng kể rủi ro khi xử lý tài sản bảo đảm nếu phát sinh nợ xấu.', 'legal_status_lookup', 82);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('81abc777-fdb1-445c-9cd8-b5763e2c6219', 'REQ-2026-2035', 'neighborhood_amenity', 'neighborhood_amenity_lookup', 'luu_y', 'Tiện ích xung quanh', '["Trường tiểu học gần nhất: 2266m · Chợ dân sinh: 1983m","Chưa có tuyến xe bus đi qua trong bán kính 1km."]', 'Mật độ tiện ích thấp hơn trung bình khu vực, có thể ảnh hưởng nhẹ đến nhu cầu ở thực so với các vị trí trung tâm hơn.', 'neighborhood_amenity_lookup', 44);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('d6b889e1-b4e1-4113-822f-66627c6a1123', 'REQ-2026-2035', 'environmental_risk', 'environmental_risk_lookup', 'da_xac_thuc', 'Môi trường', '["Không ghi nhận ngập úng trong 3 năm gần nhất.","Không nằm trong vùng cảnh báo sạt lở, ô nhiễm công nghiệp."]', 'Rủi ro môi trường ở mức thấp, không ảnh hưởng đáng kể đến giá trị định giá.', 'environmental_risk_lookup', 84);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('1586f2d4-b847-4a99-87f0-a607ce2ecb23', 'REQ-2026-2035', 'liquidity_stat', 'liquidity_stat_lookup', 'da_xac_thuc', 'Thanh khoản khu vực', '["Thời gian bán trung bình: 34 ngày · Tỷ lệ giao dịch thành công: 85%","Số tin rao bán cùng phân khúc trong bán kính 1km: 15 tin"]', 'Thanh khoản khá tốt so với mặt bằng chung phân khúc — hỗ trợ tích cực cho khả năng xử lý tài sản bảo đảm khi cần thiết.', 'liquidity_stat_lookup', 97);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('5a48d522-f7b3-4bcb-bdb0-da33aee9b265', 'REQ-2026-2035', 'stigma_reputation', 'stigma_reputation_lookup', 'da_xac_thuc', 'Dư luận / tâm linh', '["Không ghi nhận tin đồn hay sự việc bất thường liên quan tài sản/khu vực.","Không có bài báo, hồ sơ công an hoặc dữ liệu tiêu cực liên quan."]', 'Không phát hiện yếu tố bất lợi về dư luận/tâm linh — không ảnh hưởng đến giá trị hay thanh khoản.', 'stigma_reputation_lookup', 84);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('686b677c-cfd7-4d18-9240-dc883d8140ce', 'REQ-2026-2036', 'market_price', 'market_price_lookup', 'da_xac_thuc', 'Giá thị trường', '["5 giao dịch so sánh trong bán kính 1.3km."]', 'Giá giao dịch so sánh dao động 81.5–106.0 triệu/m², trung vị khoảng 98.9 triệu/m². Giá tương đối ổn định qua các giao dịch gần đây, chưa thấy biến động bất thường. Nên ưu tiên trọng số cao hơn cho các giao dịch gần đây khi đưa vào bước định giá.', 'market_price_lookup', 82);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('0e8b0ef3-3349-4ac1-9127-0113bbeae832', 'REQ-2026-2036', 'planning_zoning', 'planning_zoning_lookup', 'luu_y', 'Quy hoạch', '["Một phần thửa đất (9m²) nằm trong hành lang lộ giới quy hoạch mở rộng đường.","Chưa có quyết định thu hồi đất chính thức tại thời điểm tra cứu."]', 'Cần đối chiếu thêm bản vẽ quy hoạch chi tiết 1/500 để xác định chính xác phần diện tích ảnh hưởng trước khi đưa vào định giá.', 'planning_zoning_lookup', 64);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('2b459014-486d-4d84-9523-9e252732088f', 'REQ-2026-2036', 'legal_status', 'legal_status_lookup', 'da_xac_thuc', 'Pháp lý', '["Sổ hồng đứng tên chính chủ, cấp 23/01/2021.","Không ghi nhận tranh chấp, kê biên hay khiếu nại.","Không đang thế chấp tại tổ chức tín dụng khác."]', 'Tình trạng pháp lý sạch, đủ điều kiện nhận thế chấp. Yếu tố tích cực, giảm đáng kể rủi ro khi xử lý tài sản bảo đảm nếu phát sinh nợ xấu.', 'legal_status_lookup', 83);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('ab2ef8ef-03ee-429c-b92d-12bd8c6fae2d', 'REQ-2026-2036', 'neighborhood_amenity', 'neighborhood_amenity_lookup', 'da_xac_thuc', 'Tiện ích xung quanh', '["Trường tiểu học: 171m · Chợ dân sinh: 649m","Trạm xe bus: 225m · Bệnh viện quận: 1.6km"]', 'Mật độ tiện ích cao hơn trung bình khu vực — yếu tố hỗ trợ tích cực cho nhu cầu ở thực và thanh khoản khi cần bán lại.', 'neighborhood_amenity_lookup', 92);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('653b73fb-9954-4067-ae90-f77f35b8e678', 'REQ-2026-2036', 'environmental_risk', 'environmental_risk_lookup', 'luu_y', 'Môi trường', '["Ghi nhận ngập nhẹ cục bộ mùa mưa 2021–2025 (mức nước <20cm, rút trong ngày).","Không nằm trong vùng cảnh báo sạt lở, ô nhiễm công nghiệp."]', 'Rủi ro ngập ở mức thấp, không ảnh hưởng đáng kể đến giá trị định giá, nhưng nên khuyến nghị khách hàng mua bảo hiểm tài sản.', 'environmental_risk_lookup', 33);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('ff748021-dfd2-401f-8783-81e7760647d4', 'REQ-2026-2036', 'liquidity_stat', 'liquidity_stat_lookup', 'da_xac_thuc', 'Thanh khoản khu vực', '["Thời gian bán trung bình: 39 ngày · Tỷ lệ giao dịch thành công: 87%","Số tin rao bán cùng phân khúc trong bán kính 1km: 22 tin"]', 'Thanh khoản khá tốt so với mặt bằng chung phân khúc — hỗ trợ tích cực cho khả năng xử lý tài sản bảo đảm khi cần thiết.', 'liquidity_stat_lookup', 89);
