INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('09c6b4e6-2a18-4055-a11d-97049440dfe3', 'REQ-2026-2043', 'stigma_reputation', 'stigma_reputation_lookup', 'da_xac_thuc', 'Dư luận / tâm linh', '["Không ghi nhận tin đồn hay sự việc bất thường liên quan tài sản/khu vực.","Không có bài báo, hồ sơ công an hoặc dữ liệu tiêu cực liên quan."]', 'Không phát hiện yếu tố bất lợi về dư luận/tâm linh — không ảnh hưởng đến giá trị hay thanh khoản.', 'stigma_reputation_lookup', 91);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('f2756a6d-f434-4342-bcbe-cf21f6d8339c', 'REQ-2026-2044', 'market_price', 'market_price_lookup', 'da_xac_thuc', 'Giá thị trường', '["6 giao dịch so sánh trong bán kính 0.9km."]', 'Giá giao dịch so sánh dao động 164.7–210.5 triệu/m², trung vị khoảng 204.7 triệu/m². Xu hướng tăng theo thời gian, giao dịch gần nhất cao hơn đáng kể so với giao dịch xa nhất, cho thấy khu vực đang trong đà tăng giá. Nên ưu tiên trọng số cao hơn cho các giao dịch gần đây khi đưa vào bước định giá.', 'market_price_lookup', 71);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('ffa60f31-b782-4367-9b06-edc5ae6f935d', 'REQ-2026-2044', 'planning_zoning', 'planning_zoning_lookup', 'da_xac_thuc', 'Quy hoạch', '["Không nằm trong khu vực quy hoạch treo.","Lộ giới hẻm/đường dự kiến giữ nguyên theo đồ án quy hoạch 1/2000 phê duyệt 2020.","Không thuộc diện giải toả, thu hồi đất."]', 'Không có yếu tố quy hoạch bất lợi, có thể tăng nhẹ giá trị nếu lộ giới được mở rộng trong 2–3 năm tới nhờ cải thiện khả năng tiếp cận.', 'planning_zoning_lookup', 85);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('dc2c1acf-e80c-48c8-ae03-afdbd686a58f', 'REQ-2026-2044', 'legal_status', 'legal_status_lookup', 'luu_y', 'Pháp lý', '["Sổ hồng đứng tên chính chủ nhưng có ghi chú thế chấp đã tất toán, chưa xoá đăng ký.","Không ghi nhận tranh chấp tại thời điểm tra cứu."]', 'Cần yêu cầu khách hàng bổ sung văn bản xoá đăng ký thế chấp cũ trước khi hoàn tất hồ sơ.', 'legal_status_lookup', 48);
