INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('8725ee92-89f8-4470-8019-e50b1bd0c76e', 'REQ-2026-2044', 'environmental_risk', 'environmental_risk_lookup', 'da_xac_thuc', 'Môi trường', '["Không ghi nhận ngập úng trong 3 năm gần nhất.","Không nằm trong vùng cảnh báo sạt lở, ô nhiễm công nghiệp."]', 'Rủi ro môi trường ở mức thấp, không ảnh hưởng đáng kể đến giá trị định giá.', 'environmental_risk_lookup', 90);
