INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('e4ae4ce5-4747-4307-bb80-72b136cc8d20', 'REQ-2026-2053', 'legal_status', 'legal_status_lookup', 'luu_y', 'Pháp lý', '["Sổ hồng đứng tên chính chủ nhưng có ghi chú thế chấp đã tất toán, chưa xoá đăng ký.","Không ghi nhận tranh chấp tại thời điểm tra cứu."]', 'Cần yêu cầu khách hàng bổ sung văn bản xoá đăng ký thế chấp cũ trước khi hoàn tất hồ sơ.', 'legal_status_lookup', 31);
