INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('3d156571-e2a4-4833-b43e-0a6bf80061ba', 'REQ-2026-2054', 'planning_zoning', 'planning_zoning_lookup', 'da_xac_thuc', 'Quy hoạch', '["Không nằm trong khu vực quy hoạch treo.","Lộ giới hẻm/đường dự kiến giữ nguyên theo đồ án quy hoạch 1/2000 phê duyệt 2019.","Không thuộc diện giải toả, thu hồi đất."]', 'Không có yếu tố quy hoạch bất lợi, có thể tăng nhẹ giá trị nếu lộ giới được mở rộng trong 2–3 năm tới nhờ cải thiện khả năng tiếp cận.', 'planning_zoning_lookup', 83);
INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('0ca459a7-faa5-41f7-859b-decfbd6d1b36', 'REQ-2026-2054', 'legal_status', 'legal_status_lookup', 'da_xac_thuc', 'Pháp lý', '["Sổ hồng đứng tên chính chủ, cấp 14/01/2015.","Không ghi nhận tranh chấp, kê biên hay khiếu nại.","Không đang thế chấp tại tổ chức tín dụng khác."]', 'Tình trạng pháp lý sạch, đủ điều kiện nhận thế chấp. Yếu tố tích cực, giảm đáng kể rủi ro khi xử lý tài sản bảo đảm nếu phát sinh nợ xấu.', 'legal_status_lookup', 88);
