INSERT INTO public.lookup_finding (id, case_id, category, tool_name, status_badge, title, raw_findings, inference_text, source_label, confidence_pct) VALUES ('2a784817-3cb0-40db-b0ae-570059d1e0e0', 'REQ-2026-2054', 'liquidity_stat', 'liquidity_stat_lookup', 'luu_y', 'Thanh khoản khu vực', '["Thời gian bán trung bình: 139 ngày · Tỷ lệ giao dịch thành công: 64%","Số tin rao bán cùng phân khúc trong bán kính 1km: 5 tin"]', 'Thanh khoản thấp hơn mặt bằng chung khu vực — cần cân nhắc thêm khi xác định LTV để đảm bảo khả năng xử lý tài sản bảo đảm.', 'liquidity_stat_lookup', 58);
