INSERT INTO public.valuation_method (id, case_id, method_key, estimated_value_vnd, weight_pct, contribution_value_vnd, method_confidence_pct, inputs, inference_text, source_label) VALUES ('4c93c049-cac6-4392-b2c2-730e4c47f0ce', 'REQ-2026-2059', 'hedonic_ml', 26770000000, 31, 8298700000, 61, '["Huấn luyện trên ~1723 giao dịch lịch sử toàn khu vực (2022–2026).","R² mô hình: 0.85 · Sai số trung bình (MAE): 3.3%."]', 'Cân bằng ảnh hưởng đồng thời của nhiều yếu tố mà so sánh trực tiếp khó xử lý cùng lúc.', 'calculate_valuation — nhánh hedonic-ML (Valuation Agent)');
INSERT INTO public.valuation_method (id, case_id, method_key, estimated_value_vnd, weight_pct, contribution_value_vnd, method_confidence_pct, inputs, inference_text, source_label) VALUES ('b66ef42e-c642-4be0-83c0-5fc45c1cd11a', 'REQ-2026-2059', 'cost_approach', 26495000000, 21, 5563950000, 86, '["Đơn giá xây dựng: 8.2 triệu/m² · Khấu hao theo tuổi công trình."]', 'Cho giá trị thấp nhất/tham chiếu trong 3 phương pháp vì chưa phản ánh đầy đủ yếu tố vị trí/tiềm năng tăng giá.', 'calculate_valuation — nhánh chi phí xây dựng (Valuation Agent)');
